def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 0) return 0L
  val sieve = Array.fill(n)(true)
  sieve(0) = false
  sieve(1) = false
  val maxIndex = n - 1
  val sqrtMax = Math.sqrt(maxIndex).toInt
  for (i <- 2 to sqrtMax) {
    if (sieve(i)) {
      for (j <- i * i to maxIndex by i) {
        sieve(j) = false
      }
    }
  }
  var sumA = 0L
  var sumB = 0L
  for (i <- 0 until n) {
    if (sieve(i)) {
      sumA += nums(i)
    } else {
      sumB += nums(i)
    }
  }
  Math.abs(sumA - sumB)
}
