#include <vector>
#include <cstdlib>

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;
    int max_index = n - 1;
    std::vector<bool> sieve(max_index + 1, true);
    sieve[0] = sieve[1] = false;
    for (int i = 2; i * i <= max_index; ++i) {
        if (sieve[i]) {
            for (int j = i * i; j <= max_index; j += i) {
                sieve[j] = false;
            }
        }
    }
    long long sumA = 0, sumB = 0;
    for (int i = 0; i < n; ++i) {
        if (sieve[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }
    return std::abs(sumA - sumB);
}
